# Get info about the standoff sketches - their planes and transforms
results = {}

for sketch_name in ["SK_Standoffs", "SK_StandoffInserts"]:
    sketch = rootComp.sketches.itemByName(sketch_name)
    if sketch is None:
        results[sketch_name] = "NOT FOUND"
        continue

    t = sketch.transform
    origin = t.translation

    # Get the reference plane name if possible
    ref_plane = "unknown"
    try:
        ref_plane = sketch.referencePlane.name if sketch.referencePlane else "unknown"
    except:
        ref_plane = "N/A"

    results[sketch_name] = {
        "origin_world": [round(origin.x,4), round(origin.y,4), round(origin.z,4)],
        "referencePlane": ref_plane,
        "profile_count": sketch.profiles.count,
        "circles": [
            {
                "center_sketch": [
                    round(sketch.sketchCurves.sketchCircles.item(i).centerSketchPoint.geometry.x, 4),
                    round(sketch.sketchCurves.sketchCircles.item(i).centerSketchPoint.geometry.y, 4)
                ],
                "radius_cm": round(sketch.sketchCurves.sketchCircles.item(i).radius, 4)
            }
            for i in range(sketch.sketchCurves.sketchCircles.count)
        ]
    }

result = results

# 7.8mm diameter = 3.9mm radius = 0.39cm, exact, no tolerance
new_radius_cm = 0.39

sketches_to_update = ["SK_LidControls", "SK_PortRingAndControls"]
# Only update small control holes (r < 0.5cm), leave port ring circles alone

results = {}

for sketch_name in sketches_to_update:
    sketch = rootComp.sketches.itemByName(sketch_name)
    if sketch is None:
        results[sketch_name] = "NOT FOUND"
        continue

    updated = []
    circles = sketch.sketchCurves.sketchCircles
    for i in range(circles.count):
        circle = circles.item(i)
        old_r = round(circle.radius, 4)
        if old_r < 0.5:  # only touch control/LED holes, not the port ring
            circle.radius = new_radius_cm
            updated.append({
                "index": i,
                "old_dia_mm": round(old_r * 20, 3),
                "new_dia_mm": round(new_radius_cm * 20, 3)
            })
        else:
            updated.append({
                "index": i,
                "old_dia_mm": round(old_r * 20, 3),
                "skipped": "port ring - unchanged"
            })
    results[sketch_name] = updated

result = results

body = rootComp.bRepBodies.itemByName("Speaker_Grill")
body.isVisible = True
result = {"visible": body.isVisible, "name": body.name}
